code = """import json
import re

# Get the file path from storage
file_path = locals()['var_functions.query_db:5']

# Read the full JSON file
with open(file_path, 'r') as f:
    articles = json.load(f)

# Check articles that mention sports terms
sports_articles = []

for article in articles:
    title = article.get('title', '').lower()
    description = article.get('description', '').lower()
    
    # Check for clear sports indicators
    clear_sports_terms = ['football', 'soccer', 'basketball', 'tennis', 'golf', 'cricket',
                          'hockey', 'rugby', 'olympics', 'olympic', 'nba ', 'nfl ', 'mlb ', 'nhl',
                          'world cup', 'marathon', 'championship', 'tournament', 'coach ', 'player ',
                          'athlete', 'game ', 'games ']
    
    # Look for articles that are clearly about sports
    for term in clear_sports_terms:
        if term in title or term in description:
            # Make sure it's not a false positive (e.g., "Olympics" mentioned in passing about security)
            if 'olympic' in title or 'olympic' in description:
                if 'security' in description and 'sport' not in description:
                    continue  # Skip articles just about Olympic security
            
            sports_articles.append(article)
            break

# Find the sports article with longest description
max_len = -1
best_sports_article = None

for article in sports_articles:
    desc_len = len(article.get('description', ''))
    if desc_len > max_len:
        max_len = desc_len
        best_sports_article = article

# Display some sports articles to verify
sample_sports = [{
    'title': article['title'], 
    'description_length': len(article['description']),
    'id': article['article_id']
} for article in sports_articles[:20]]

result = {
    'sports_articles_count': len(sports_articles),
    'best_sports_title': best_sports_article['title'] if best_sports_article else None,
    'best_sports_description_length': max_len,
    'best_sports_article_id': best_sports_article['article_id'] if best_sports_article else None,
    'sample_sports': sample_sports
}

print('__RESULT__:')
print(json.dumps(result, indent=2))"""

